module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [3:0] cnt;
    reg [15:0] sr;
    reg [15:0] neg_divisor;
    reg [15:0] quotient, remainder;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            cnt <= 4'b0;
            sr <= 16'b0;
            neg_divisor <= 16'b0;
            quotient <= 16'b0;
            remainder <= 16'b0;
            res_valid <= 1'b0;
        end else if (opn_valid) begin
            if (cnt == 4'b1000) begin
                cnt <= 4'b0;
                sr <= {neg_divisor, sr[15:1]};
                quotient <= sr[7:0];
                remainder <= sr[15:8];
                res_valid <= 1'b1;
            end else begin
                cnt <= cnt + 4'b1;
                if (sign && dividend[7]) begin
                    sr <= {~{8'b0, dividend}, 1'b0};
                end else begin
                    sr <= {dividend, 1'b0};
                end
                if (sign && divisor[7]) begin
                    neg_divisor <= ~{1'b0, divisor} + 16'b1;
                end else begin
                    neg_divisor <= ~{1'b0, divisor};
                end
            end
        end else if (res_ready) begin
            res_valid <= 1'b0;
        end
    end

    always @(*) begin
        if (cnt == 4'b1000) begin
            result = {remainder, quotient};
        end else begin
            result = 16'b0;
        end
    end

endmodule
